package com.babidndn.order;
import jakarta.persistence.*;import java.time.LocalDateTime;import java.util.*;
@Entity public class CustomerOrder { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false,unique=true) private String orderNumber; @Enumerated(EnumType.STRING) private OrderStatus status=OrderStatus.ORDERED; private int totalAmount; private LocalDateTime createdAt=LocalDateTime.now(); @OneToMany(mappedBy="order",cascade=CascadeType.ALL,orphanRemoval=true) private List<OrderItem> items=new ArrayList<>(); protected CustomerOrder(){} public CustomerOrder(String orderNumber,int totalAmount){this.orderNumber=orderNumber;this.totalAmount=totalAmount;} public Long getId(){return id;} public String getOrderNumber(){return orderNumber;} public OrderStatus getStatus(){return status;} public int getTotalAmount(){return totalAmount;} public LocalDateTime getCreatedAt(){return createdAt;} public List<OrderItem> getItems(){return items;} public void addItem(OrderItem item){items.add(item);item.setOrder(this);} public void changeStatus(OrderStatus status){this.status=status;} }
